Storing encrypted credit card data requires careful key management. A common but dangerous mistake is hard-coding encryption keys directly in source code, which exposes them to anyone with repository access.

**VULNERABLE CODE**:

```javascript
const crypto = require('crypto');

// DANGEROUS: Hard-coded encryption key in source code
const ENCRYPTION_KEY = 'MySecretKey12345MySecretKey12345'; // 32 bytes for AES-256
const IV = 'InitVector123456'; // 16 bytes - also hard-coded!

function encryptCreditCard(cardNumber) {
  const cipher = crypto.createCipheriv('aes-256-cbc', ENCRYPTION_KEY, IV);
  let encrypted = cipher.update(cardNumber, 'utf8', 'hex');
  encrypted += cipher.final('hex');
  return encrypted;
}

function decryptCreditCard(encryptedCard) {
  const decipher = crypto.createDecipheriv('aes-256-cbc', ENCRYPTION_KEY, IV);
  let decrypted = decipher.update(encryptedCard, 'hex', 'utf8');
  decrypted += decipher.final('utf8');
  return decrypted;
}

// Usage in Express route
app.post('/api/payment', (req, res) => {
  const { cardNumber } = req.body;
  const encryptedCard = encryptCreditCard(cardNumber);
  // Store encryptedCard in database
  db.query('INSERT INTO payments (card_encrypted) VALUES (?)', [encryptedCard]);
  res.json({ success: true });
});
```

**Attack Scenario**:
```bash
# Attacker clones repository or decompiles bundled JavaScript
git clone https://github.com/company/payment-app.git
grep -r "ENCRYPTION_KEY" ./payment-app
# Output: const ENCRYPTION_KEY = 'MySecretKey12345MySecretKey12345';

# Attacker now decrypts all stolen encrypted card data
node -e "const crypto = require('crypto'); const key = 'MySecretKey12345MySecretKey12345'; const iv = 'InitVector123456'; const d = crypto.createDecipheriv('aes-256-cbc', key, iv); console.log(d.update('STOLEN_ENCRYPTED_DATA', 'hex', 'utf8') + d.final('utf8'));"
```

**Why This Is Dangerous**:
- Keys in source code are committed to version control history forever
- Anyone with repository access (employees, contractors, attackers) can extract keys
- Compiled/bundled JavaScript can be deobfuscated to reveal keys
- Static IV with CBC mode enables pattern analysis attacks
- Key rotation requires code changes and redeployment

**SECURE VERSION**:

```javascript
const crypto = require('crypto');

class SecureEncryption {
  constructor() {
    // Load key from environment variable - NEVER hard-code
    this.encryptionKey = process.env.ENCRYPTION_KEY;

    if (!this.encryptionKey) {
      throw new Error('ENCRYPTION_KEY environment variable is required');
    }

    // Validate key length for AES-256
    if (Buffer.from(this.encryptionKey, 'base64').length !== 32) {
      throw new Error('ENCRYPTION_KEY must be 32 bytes (256 bits) base64 encoded');
    }
  }

  encrypt(plaintext) {
    // Generate random IV for each encryption - critical for security
    const iv = crypto.randomBytes(16);
    const key = Buffer.from(this.encryptionKey, 'base64');

    const cipher = crypto.createCipheriv('aes-256-gcm', key, iv);
    let encrypted = cipher.update(plaintext, 'utf8', 'hex');
    encrypted += cipher.final('hex');

    // Get authentication tag for GCM mode
    const authTag = cipher.getAuthTag().toString('hex');

    // Return IV + authTag + ciphertext (IV is not secret, must be stored)
    return iv.toString('hex') + ':' + authTag + ':' + encrypted;
  }

  decrypt(encryptedData) {
    const parts = encryptedData.split(':');
    if (parts.length !== 3) {
      throw new Error('Invalid encrypted data format');
    }

    const iv = Buffer.from(parts[0], 'hex');
    const authTag = Buffer.from(parts[1], 'hex');
    const encrypted = parts[2];
    const key = Buffer.from(this.encryptionKey, 'base64');

    const decipher = crypto.createDecipheriv('aes-256-gcm', key, iv);
    decipher.setAuthTag(authTag);

    let decrypted = decipher.update(encrypted, 'hex', 'utf8');
    decrypted += decipher.final('utf8');

    return decrypted;
  }
}

module.exports = SecureEncryption;
```

**Key Security Controls**:
- **Environment variables**: Keys loaded from `process.env`, never in code
- **Random IV per encryption**: Prevents pattern analysis; IV stored with ciphertext
- **AES-256-GCM mode**: Authenticated encryption prevents tampering, superior to CBC
- **Key validation**: Fails fast if key is missing or wrong length
- **Auth tag verification**: GCM mode detects any ciphertext modification

Key rotation and distributed key management are critical for production systems. You need a secrets management solution that handles key versioning, automatic rotation, and secure distribution.

**PRODUCTION PATTERN**:

```javascript
const crypto = require('crypto');
const { SecretsManagerClient, GetSecretValueCommand } = require('@aws-sdk/client-secrets-manager');

class ProductionKeyManager {
  constructor(options = {}) {
    this.secretsClient = new SecretsManagerClient({ 
      region: process.env.AWS_REGION || 'us-east-1' 
    });
    this.secretName = options.secretName || 'app/encryption-keys';
    this.keys = new Map(); // Cache: keyVersion -> keyBuffer
    this.currentKeyVersion = null;
    this.keyRefreshInterval = options.refreshInterval || 300000; // 5 minutes
    this.logger = options.logger || console;
  }

  async initialize() {
    await this.refreshKeys();
    // Periodic key refresh to pick up rotations
    setInterval(() => this.refreshKeys(), this.keyRefreshInterval);
    this.logger.info('Key manager initialized', { 
      currentVersion: this.currentKeyVersion,
      cachedVersions: Array.from(this.keys.keys())
    });
  }

  async refreshKeys() {
    try {
      const command = new GetSecretValueCommand({ SecretId: this.secretName });
      const response = await this.secretsClient.send(command);
      const secrets = JSON.parse(response.SecretString);

      // Support multiple key versions for rotation
      // Format: { "v1": "base64key...", "v2": "base64key...", "current": "v2" }
      for (const [version, keyBase64] of Object.entries(secrets)) {
        if (version !== 'current') {
          this.keys.set(version, Buffer.from(keyBase64, 'base64'));
        }
      }
      this.currentKeyVersion = secrets.current;

      this.logger.info('Keys refreshed successfully', {
        versions: Array.from(this.keys.keys()),
        currentVersion: this.currentKeyVersion
      });
    } catch (error) {
      this.logger.error('Failed to refresh encryption keys', { error: error.message });
      // Don't crash if we have cached keys
      if (this.keys.size === 0) {
        throw new Error('No encryption keys available');
      }
    }
  }

  getCurrentKey() {
    const key = this.keys.get(this.currentKeyVersion);
    if (!key) {
      throw new Error(`Current key version ${this.currentKeyVersion} not found`);
    }
    return { version: this.currentKeyVersion, key };
  }

  getKeyByVersion(version) {
    const key = this.keys.get(version);
    if (!key) {
      throw new Error(`Key version ${version} not found - may need re-encryption`);
    }
    return key;
  }
}

class ProductionEncryptionService {
  constructor(keyManager, logger) {
    this.keyManager = keyManager;
    this.logger = logger || console;
    this.algorithm = 'aes-256-gcm';
  }

  encrypt(plaintext, context = {}) {
    const startTime = Date.now();
    const { version, key } = this.keyManager.getCurrentKey();
    const iv = crypto.randomBytes(12); // 96 bits recommended for GCM

    const cipher = crypto.createCipheriv(this.algorithm, key, iv);

    // Add AAD (Additional Authenticated Data) for context binding
    const aad = Buffer.from(JSON.stringify({
      purpose: context.purpose || 'general',
      timestamp: Date.now()
    }));
    cipher.setAAD(aad);

    let encrypted = cipher.update(plaintext, 'utf8');
    encrypted = Buffer.concat([encrypted, cipher.final()]);
    const authTag = cipher.getAuthTag();

    // Format: version:iv:authTag:aad:ciphertext (all hex encoded)
    const result = [
      version,
      iv.toString('hex'),
      authTag.toString('hex'),
      aad.toString('hex'),
      encrypted.toString('hex')
    ].join(':');

    // Audit logging for compliance
    this.logger.info('Encryption performed', {
      keyVersion: version,
      dataLength: plaintext.length,
      purpose: context.purpose,
      durationMs: Date.now() - startTime
    });

    return result;
  }

  decrypt(encryptedData, context = {}) {
    const startTime = Date.now();
    const parts = encryptedData.split(':');

    if (parts.length !== 5) {
      this.logger.warn('Invalid encrypted data format', { 
        partsCount: parts.length,
        expected: 5 
      });
      throw new Error('Invalid encrypted data format');
    }

    const [version, ivHex, authTagHex, aadHex, ciphertextHex] = parts;

    try {
      const key = this.keyManager.getKeyByVersion(version);
      const iv = Buffer.from(ivHex, 'hex');
      const authTag = Buffer.from(authTagHex, 'hex');
      const aad = Buffer.from(aadHex, 'hex');
      const ciphertext = Buffer.from(ciphertextHex, 'hex');

      const decipher = crypto.createDecipheriv(this.algorithm, key, iv);
      decipher.setAAD(aad);
      decipher.setAuthTag(authTag);

      let decrypted = decipher.update(ciphertext);
      decrypted = Buffer.concat([decrypted, decipher.final()]);

      this.logger.info('Decryption performed', {
        keyVersion: version,
        durationMs: Date.now() - startTime
      });

      return decrypted.toString('utf8');
    } catch (error) {
      this.logger.error('Decryption failed', {
        keyVersion: version,
        error: error.message,
        possibleTampering: error.message.includes('auth')
      });
      throw new Error('Decryption failed - data may be corrupted or tampered');
    }
  }

  // Re-encrypt data with current key (for key rotation)
  async reencrypt(encryptedData, context = {}) {
    const parts = encryptedData.split(':');
    const currentVersion = this.keyManager.currentKeyVersion;

    // Skip if already using current key
    if (parts[0] === currentVersion) {
      return encryptedData;
    }

    const plaintext = this.decrypt(encryptedData, context);
    const newEncrypted = this.encrypt(plaintext, context);

    this.logger.info('Data re-encrypted', {
      oldVersion: parts[0],
      newVersion: currentVersion
    });

    return newEncrypted;
  }
}

// Application initialization
async function initializeApp() {
  const logger = require('pino')({ level: 'info' });

  const keyManager = new ProductionKeyManager({
    secretName: process.env.SECRETS_NAME || 'prod/app/encryption-keys',
    refreshInterval: 300000,
    logger
  });

  await keyManager.initialize();

  const encryptionService = new ProductionEncryptionService(keyManager, logger);

  return { keyManager, encryptionService, logger };
}

module.exports = { ProductionKeyManager, ProductionEncryptionService, initializeApp };
```

**Defense in Depth Layers**:

1. **Secrets Management Service** (AWS Secrets Manager, HashiCorp Vault):
```javascript
// Keys never touch disk or source code
// Automatic rotation policies
// Access audit trails
// IAM-based access control
const command = new GetSecretValueCommand({ 
  SecretId: this.secretName,
  VersionStage: 'AWSCURRENT' // Or 'AWSPENDING' during rotation
});
```

2. **Key Versioning for Seamless Rotation**:
```javascript
// Encrypted data includes key version
// Old keys kept for decryption during transition
// Background job re-encrypts old data
const result = `${version}:${iv}:${authTag}:${aad}:${ciphertext}`;
```

3. **Authenticated Encryption with AAD**:
```javascript
// Context binding prevents ciphertext from being used in wrong context
const aad = Buffer.from(JSON.stringify({
  purpose: 'credit_card',
  userId: user.id,
  timestamp: Date.now()
}));
cipher.setAAD(aad);
```

**Additional Protections**:
- **Memory protection**: Clear sensitive buffers after use with `crypto.timingSafeEqual()` for comparisons
- **Key derivation**: Use HKDF to derive purpose-specific keys from master key
- **Monitoring**: Alert on decryption failures (possible tampering), unusual volumes
- **Compliance**: PCI-DSS requires encryption keys to be stored separately from data
- **Key ceremony**: Document key generation process, require multi-party authorization
- **HSM integration**: For highest security, use AWS CloudHSM or Azure Dedicated HSM for key operations

Never hard-code encryption keys in your source code. This is one of the most critical cryptographic failures because anyone with access to your compiled code (JAR files, APKs, decompiled classes) can extract the key and decrypt all your data.

**VULNERABLE CODE**:

```java
import javax.crypto.Cipher;
import javax.crypto.spec.SecretKeySpec;
import javax.crypto.spec.IvParameterSpec;
import java.util.Base64;
import java.nio.charset.StandardCharsets;

public class VulnerableEncryptionService {

    // CRITICAL VULNERABILITY: Hard-coded encryption key
    private static final String ENCRYPTION_KEY = "MyS3cr3tK3y12345";
    private static final String IV = "RandomInitVector";

    public String encryptApiKey(String apiKey) throws Exception {
        SecretKeySpec keySpec = new SecretKeySpec(
            ENCRYPTION_KEY.getBytes(StandardCharsets.UTF_8), "AES");
        IvParameterSpec ivSpec = new IvParameterSpec(
            IV.getBytes(StandardCharsets.UTF_8));

        Cipher cipher = Cipher.getInstance("AES/CBC/PKCS5Padding");
        cipher.init(Cipher.ENCRYPT_MODE, keySpec, ivSpec);

        byte[] encrypted = cipher.doFinal(apiKey.getBytes(StandardCharsets.UTF_8));
        return Base64.getEncoder().encodeToString(encrypted);
    }

    public String decryptApiKey(String encryptedKey) throws Exception {
        SecretKeySpec keySpec = new SecretKeySpec(
            ENCRYPTION_KEY.getBytes(StandardCharsets.UTF_8), "AES");
        IvParameterSpec ivSpec = new IvParameterSpec(
            IV.getBytes(StandardCharsets.UTF_8));

        Cipher cipher = Cipher.getInstance("AES/CBC/PKCS5Padding");
        cipher.init(Cipher.DECRYPT_MODE, keySpec, ivSpec);

        byte[] decoded = Base64.getDecoder().decode(encryptedKey);
        return new String(cipher.doFinal(decoded), StandardCharsets.UTF_8);
    }
}
```

**Attack Method**:
```bash
# Decompile the JAR to extract the key
jd-cli application.jar -od decompiled/
grep -r "ENCRYPTION_KEY\|SecretKeySpec" decompiled/

# Or use jadx for Android APKs
jadx -d output/ app.apk
grep -r "AES\|encryption" output/
```

**Why This Is Dangerous**:
- Key is visible in decompiled bytecode - Java class files are easily decompiled
- Same key across all deployments means one breach exposes everything
- Static IV violates cryptographic best practices (enables pattern analysis)
- Version control systems will contain key history forever
- No key rotation possible without code redeployment

**SECURE VERSION**:

```java
import javax.crypto.Cipher;
import javax.crypto.SecretKey;
import javax.crypto.spec.GCMParameterSpec;
import java.security.SecureRandom;
import java.util.Base64;
import java.nio.charset.StandardCharsets;
import java.util.logging.Logger;

public class SecureEncryptionService {

    private static final Logger logger = Logger.getLogger(
        SecureEncryptionService.class.getName());
    private static final int GCM_IV_LENGTH = 12;
    private static final int GCM_TAG_LENGTH = 128;

    private final KeyProvider keyProvider;
    private final SecureRandom secureRandom;

    public SecureEncryptionService(KeyProvider keyProvider) {
        this.keyProvider = keyProvider;
        this.secureRandom = new SecureRandom();
    }

    public String encrypt(String plaintext, String keyId) throws Exception {
        // Retrieve key from external secure storage
        SecretKey key = keyProvider.getKey(keyId);

        // Generate random IV for each encryption
        byte[] iv = new byte[GCM_IV_LENGTH];
        secureRandom.nextBytes(iv);

        GCMParameterSpec gcmSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);

        Cipher cipher = Cipher.getInstance("AES/GCM/NoPadding");
        cipher.init(Cipher.ENCRYPT_MODE, key, gcmSpec);

        byte[] ciphertext = cipher.doFinal(
            plaintext.getBytes(StandardCharsets.UTF_8));

        // Prepend IV to ciphertext
        byte[] combined = new byte[iv.length + ciphertext.length];
        System.arraycopy(iv, 0, combined, 0, iv.length);
        System.arraycopy(ciphertext, 0, combined, iv.length, ciphertext.length);

        logger.fine("Data encrypted with key: " + keyId);
        return Base64.getEncoder().encodeToString(combined);
    }

    public String decrypt(String encryptedData, String keyId) throws Exception {
        SecretKey key = keyProvider.getKey(keyId);

        byte[] combined = Base64.getDecoder().decode(encryptedData);

        // Extract IV from beginning
        byte[] iv = new byte[GCM_IV_LENGTH];
        byte[] ciphertext = new byte[combined.length - GCM_IV_LENGTH];
        System.arraycopy(combined, 0, iv, 0, iv.length);
        System.arraycopy(combined, iv.length, ciphertext, 0, ciphertext.length);

        GCMParameterSpec gcmSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);

        Cipher cipher = Cipher.getInstance("AES/GCM/NoPadding");
        cipher.init(Cipher.DECRYPT_MODE, key, gcmSpec);

        return new String(cipher.doFinal(ciphertext), StandardCharsets.UTF_8);
    }
}
```

**Key Security Controls**:
- **External Key Storage**: Keys retrieved from external KeyProvider (HSM, KMS, Vault)
- **AES-GCM Mode**: Provides both confidentiality and integrity/authenticity
- **Random IV Per Encryption**: Prevents pattern analysis and replay attacks
- **Key Identification**: Support for multiple keys and key rotation via keyId parameter

Excellent question. Production key management requires external secure storage with proper access controls, audit logging, and key lifecycle management. Here are multiple production-ready implementations.

**PRODUCTION PATTERN**:

```java
import javax.crypto.SecretKey;
import javax.crypto.spec.SecretKeySpec;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import java.util.logging.Logger;
import java.time.Instant;

// Key provider interface for abstraction
public interface KeyProvider {
    SecretKey getKey(String keyId) throws KeyNotFoundException;
    void rotateKey(String keyId) throws KeyManagementException;
    KeyMetadata getKeyMetadata(String keyId) throws KeyNotFoundException;
}

// AWS KMS Implementation
import software.amazon.awssdk.services.kms.KmsClient;
import software.amazon.awssdk.services.kms.model.*;
import software.amazon.awssdk.core.SdkBytes;

public class AwsKmsKeyProvider implements KeyProvider {

    private static final Logger logger = Logger.getLogger(
        AwsKmsKeyProvider.class.getName());

    private final KmsClient kmsClient;
    private final Map<String, CachedKey> keyCache;
    private final long cacheTtlMillis;

    public AwsKmsKeyProvider(KmsClient kmsClient, long cacheTtlSeconds) {
        this.kmsClient = kmsClient;
        this.keyCache = new ConcurrentHashMap<>();
        this.cacheTtlMillis = cacheTtlSeconds * 1000;
    }

    @Override
    public SecretKey getKey(String keyId) throws KeyNotFoundException {
        // Check cache first
        CachedKey cached = keyCache.get(keyId);
        if (cached != null && !cached.isExpired()) {
            logger.fine("Using cached data key for: " + keyId);
            return cached.getKey();
        }

        try {
            // Generate a new data key from KMS
            GenerateDataKeyRequest request = GenerateDataKeyRequest.builder()
                .keyId(keyId)
                .keySpec(DataKeySpec.AES_256)
                .build();

            GenerateDataKeyResponse response = kmsClient.generateDataKey(request);

            byte[] plaintextKey = response.plaintext().asByteArray();
            SecretKey secretKey = new SecretKeySpec(plaintextKey, "AES");

            // Cache the key with encrypted version for potential re-fetch
            keyCache.put(keyId, new CachedKey(
                secretKey, 
                response.ciphertextBlob().asByteArray(),
                System.currentTimeMillis() + cacheTtlMillis
            ));

            logger.info("Generated new data key from KMS: " + keyId);
            return secretKey;

        } catch (KmsException e) {
            logger.severe("Failed to retrieve key from KMS: " + e.getMessage());
            throw new KeyNotFoundException("Key not found: " + keyId, e);
        }
    }

    @Override
    public void rotateKey(String keyId) throws KeyManagementException {
        // Invalidate cached key to force refresh
        keyCache.remove(keyId);
        logger.info("Key cache invalidated for rotation: " + keyId);
    }

    @Override
    public KeyMetadata getKeyMetadata(String keyId) throws KeyNotFoundException {
        DescribeKeyRequest request = DescribeKeyRequest.builder()
            .keyId(keyId)
            .build();

        try {
            DescribeKeyResponse response = kmsClient.describeKey(request);
            return new KeyMetadata(
                response.keyMetadata().keyId(),
                response.keyMetadata().creationDate(),
                response.keyMetadata().keyStateAsString()
            );
        } catch (KmsException e) {
            throw new KeyNotFoundException("Key metadata not found: " + keyId, e);
        }
    }

    private static class CachedKey {
        private final SecretKey key;
        private final byte[] encryptedKey;
        private final long expiryTime;

        CachedKey(SecretKey key, byte[] encryptedKey, long expiryTime) {
            this.key = key;
            this.encryptedKey = encryptedKey;
            this.expiryTime = expiryTime;
        }

        SecretKey getKey() { return key; }
        boolean isExpired() { return System.currentTimeMillis() > expiryTime; }
    }
}

// HashiCorp Vault Implementation
import io.github.jopenlibs.vault.Vault;
import io.github.jopenlibs.vault.VaultConfig;
import io.github.jopenlibs.vault.response.LogicalResponse;

public class VaultKeyProvider implements KeyProvider {

    private static final Logger logger = Logger.getLogger(
        VaultKeyProvider.class.getName());

    private final Vault vault;
    private final String secretPath;

    public VaultKeyProvider(String vaultAddress, String token, String secretPath) 
            throws Exception {
        VaultConfig config = new VaultConfig()
            .address(vaultAddress)
            .token(token)
            .engineVersion(2)
            .build();

        this.vault = Vault.create(config);
        this.secretPath = secretPath;
    }

    @Override
    public SecretKey getKey(String keyId) throws KeyNotFoundException {
        try {
            String path = secretPath + "/" + keyId;
            LogicalResponse response = vault.logical().read(path);

            if (response.getData() == null || !response.getData().containsKey("key")) {
                throw new KeyNotFoundException("Key not found in Vault: " + keyId);
            }

            String base64Key = response.getData().get("key");
            byte[] keyBytes = java.util.Base64.getDecoder().decode(base64Key);

            logger.info("Retrieved key from Vault: " + keyId);
            return new SecretKeySpec(keyBytes, "AES");

        } catch (Exception e) {
            logger.severe("Vault key retrieval failed: " + e.getMessage());
            throw new KeyNotFoundException("Failed to retrieve key: " + keyId, e);
        }
    }

    @Override
    public void rotateKey(String keyId) throws KeyManagementException {
        // Vault Transit engine supports automatic rotation
        try {
            vault.logical().write("transit/keys/" + keyId + "/rotate", null);
            logger.info("Key rotated in Vault: " + keyId);
        } catch (Exception e) {
            throw new KeyManagementException("Key rotation failed: " + keyId, e);
        }
    }

    @Override
    public KeyMetadata getKeyMetadata(String keyId) throws KeyNotFoundException {
        // Implementation for Vault key metadata
        return new KeyMetadata(keyId, Instant.now(), "ENABLED");
    }
}

// Environment-based provider for development/testing
public class EnvironmentKeyProvider implements KeyProvider {

    private static final Logger logger = Logger.getLogger(
        EnvironmentKeyProvider.class.getName());

    @Override
    public SecretKey getKey(String keyId) throws KeyNotFoundException {
        String envVarName = "ENCRYPTION_KEY_" + keyId.toUpperCase().replace("-", "_");
        String base64Key = System.getenv(envVarName);

        if (base64Key == null || base64Key.isEmpty()) {
            throw new KeyNotFoundException(
                "Environment variable not set: " + envVarName);
        }

        byte[] keyBytes = java.util.Base64.getDecoder().decode(base64Key);

        if (keyBytes.length != 32) {
            throw new KeyNotFoundException(
                "Invalid key length. Expected 256 bits (32 bytes)");
        }

        logger.fine("Retrieved key from environment: " + keyId);
        return new SecretKeySpec(keyBytes, "AES");
    }

    @Override
    public void rotateKey(String keyId) throws KeyManagementException {
        throw new KeyManagementException(
            "Key rotation not supported in environment provider");
    }

    @Override
    public KeyMetadata getKeyMetadata(String keyId) throws KeyNotFoundException {
        return new KeyMetadata(keyId, Instant.now(), "STATIC");
    }
}

// Factory for selecting appropriate provider based on environment
public class KeyProviderFactory {

    public static KeyProvider create() {
        String env = System.getenv("APP_ENVIRONMENT");

        if ("production".equals(env)) {
            // Use AWS KMS in production
            KmsClient kmsClient = KmsClient.builder().build();
            return new AwsKmsKeyProvider(kmsClient, 300); // 5 min cache

        } else if ("staging".equals(env)) {
            // Use Vault in staging
            try {
                return new VaultKeyProvider(
                    System.getenv("VAULT_ADDR"),
                    System.getenv("VAULT_TOKEN"),
                    "secret/encryption-keys"
                );
            } catch (Exception e) {
                throw new RuntimeException("Failed to initialize Vault", e);
            }

        } else {
            // Use environment variables in development
            return new EnvironmentKeyProvider();
        }
    }
}
```

**Defense in Depth Layers**:

1. **External Key Storage**: Keys never exist in source code or configuration files
```java
// Keys come from external systems with their own access controls
SecretKey key = keyProvider.getKey(keyId);  // KMS, Vault, HSM
```

2. **Key Caching with TTL**: Reduces external calls while limiting exposure window
```java
if (cached != null && !cached.isExpired()) {
    return cached.getKey();  // Use cached key if still valid
}
```

3. **Key Rotation Support**: Enable key rotation without code changes
```java
public void rotateKey(String keyId) throws KeyManagementException {
    keyCache.remove(keyId);  // Force refresh on next access
}
```

**Additional Protections**:

- **Audit Logging**: All key access is logged for compliance (SOC2, PCI-DSS)
- **IAM Policies**: Restrict which services/users can access which keys
- **Key Versioning**: KMS and Vault support multiple key versions for gradual rotation
- **Envelope Encryption**: Use KMS to encrypt data keys, store encrypted keys locally
- **Memory Protection**: Consider using `char[]` and explicit clearing after use
- **Hardware Security Modules (HSM)**: For highest security requirements, keys never leave hardware

**Key Rotation Strategy**:
```java
// Support for graceful key rotation with versioning
public String encryptWithVersion(String plaintext, String keyId) {
    // Always encrypt with latest key version
    String ciphertext = encrypt(plaintext, keyId);
    int currentVersion = keyProvider.getCurrentVersion(keyId);
    return currentVersion + ":" + ciphertext;
}

public String decryptWithVersion(String versionedCiphertext, String keyId) {
    String[] parts = versionedCiphertext.split(":", 2);
    int version = Integer.parseInt(parts[0]);
    // Decrypt with specific version for backward compatibility
    return decrypt(parts[1], keyId, version);
}
```

Hard-coding encryption keys directly in source code is one of the most dangerous cryptographic failures. Once your binary is distributed or source code is accessed, the key is permanently compromised.

**VULNERABLE CODE**:

```go
package main

import (
	"crypto/aes"
	"crypto/cipher"
	"crypto/rand"
	"encoding/base64"
	"fmt"
	"io"
)

// DANGER: Hard-coded encryption key in source code
const encryptionKey = "my-super-secret-32-byte-key!!!!!"

func encryptData(plaintext string) (string, error) {
	block, err := aes.NewCipher([]byte(encryptionKey))
	if err != nil {
		return "", err
	}

	gcm, err := cipher.NewGCM(block)
	if err != nil {
		return "", err
	}

	nonce := make([]byte, gcm.NonceSize())
	if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
		return "", err
	}

	ciphertext := gcm.Seal(nonce, nonce, []byte(plaintext), nil)
	return base64.StdEncoding.EncodeToString(ciphertext), nil
}

func decryptData(encrypted string) (string, error) {
	data, err := base64.StdEncoding.DecodeString(encrypted)
	if err != nil {
		return "", err
	}

	block, err := aes.NewCipher([]byte(encryptionKey))
	if err != nil {
		return "", err
	}

	gcm, err := cipher.NewGCM(block)
	if err != nil {
		return "", err
	}

	nonceSize := gcm.NonceSize()
	nonce, ciphertext := data[:nonceSize], data[nonceSize:]

	plaintext, err := gcm.Open(nil, nonce, ciphertext, nil)
	return string(plaintext), err
}
```

**Attack Method**:
```bash
# Extract strings from compiled Go binary
strings -n 16 vulnerable_app | grep -E "^[A-Za-z0-9!@#$%^&*()-_=+]{32}$"

