**Why This Is Dangerous**:
- Keys are embedded in compiled binaries and easily extracted with `strings` command
- Source code in version control exposes keys to all developers and potential leaks
- Key rotation requires rebuilding and redeploying the entire application
- Single key compromise decrypts ALL data ever encrypted with it
- Cannot revoke access without changing the key everywhere

**SECURE VERSION**:

```go
package main

import (
	"context"
	"crypto/aes"
	"crypto/cipher"
	"crypto/rand"
	"encoding/base64"
	"fmt"
	"io"
	"os"

	secretmanager "cloud.google.com/go/secretmanager/apiv1"
	secretmanagerpb "cloud.google.com/go/secretmanager/apiv1/secretmanagerpb"
)

type SecureEncryptor struct {
	key []byte
}

// NewSecureEncryptor loads encryption key from environment or secret manager
func NewSecureEncryptor(ctx context.Context) (*SecureEncryptor, error) {
	var key []byte
	var err error

	// Option 1: Load from environment variable (for development)
	if envKey := os.Getenv("ENCRYPTION_KEY"); envKey != "" {
		key, err = base64.StdEncoding.DecodeString(envKey)
		if err != nil {
			return nil, fmt.Errorf("invalid base64 key: %w", err)
		}
	} else {
		// Option 2: Load from secret manager (for production)
		key, err = loadKeyFromSecretManager(ctx)
		if err != nil {
			return nil, fmt.Errorf("failed to load key from secret manager: %w", err)
		}
	}

	// Validate key length for AES-256
	if len(key) != 32 {
		return nil, fmt.Errorf("encryption key must be 32 bytes for AES-256")
	}

	return &SecureEncryptor{key: key}, nil
}

func loadKeyFromSecretManager(ctx context.Context) ([]byte, error) {
	client, err := secretmanager.NewClient(ctx)
	if err != nil {
		return nil, err
	}
	defer client.Close()

	projectID := os.Getenv("GCP_PROJECT_ID")
	secretName := os.Getenv("ENCRYPTION_KEY_SECRET_NAME")

	req := &secretmanagerpb.AccessSecretVersionRequest{
		Name: fmt.Sprintf("projects/%s/secrets/%s/versions/latest", projectID, secretName),
	}

	result, err := client.AccessSecretVersion(ctx, req)
	if err != nil {
		return nil, err
	}

	return result.Payload.Data, nil
}

func (e *SecureEncryptor) Encrypt(plaintext string) (string, error) {
	block, err := aes.NewCipher(e.key)
	if err != nil {
		return "", err
	}

	gcm, err := cipher.NewGCM(block)
	if err != nil {
		return "", err
	}

	nonce := make([]byte, gcm.NonceSize())
	if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
		return "", err
	}

	ciphertext := gcm.Seal(nonce, nonce, []byte(plaintext), nil)
	return base64.StdEncoding.EncodeToString(ciphertext), nil
}
