**Key Security Controls**:
- **External Key Storage**: Keys loaded from environment variables or secret managers, never in code
- **Key Validation**: Verifies key length matches cryptographic requirements (32 bytes for AES-256)
- **Secure Defaults**: Production uses secret manager; environment variables only for development

Key rotation is critical for limiting the blast radius of a key compromise and meeting compliance requirements. Here's a production-ready pattern that supports multiple key versions.

**PRODUCTION PATTERN**:

```go
package crypto

import (
	"context"
	"crypto/aes"
	"crypto/cipher"
	"crypto/rand"
	"encoding/base64"
	"encoding/binary"
	"errors"
	"fmt"
	"io"
	"log/slog"
	"sync"
	"time"
)

var (
	ErrKeyNotFound     = errors.New("encryption key version not found")
	ErrInvalidKeyID    = errors.New("invalid key ID in ciphertext")
	ErrDecryptionFailed = errors.New("decryption failed")
)

// KeyVersion represents a single encryption key with metadata
type KeyVersion struct {
	ID        uint32
	Key       []byte
	CreatedAt time.Time
	ExpiresAt time.Time
	Status    string // "active", "decrypt-only", "retired"
}

// KeyManager handles key rotation and versioning
type KeyManager struct {
	mu            sync.RWMutex
	keys          map[uint32]*KeyVersion
	activeKeyID   uint32
	keyProvider   KeyProvider
	logger        *slog.Logger
	rotationCheck time.Duration
}

// KeyProvider interface for external key storage
type KeyProvider interface {
	GetKey(ctx context.Context, keyID uint32) ([]byte, error)
	GetActiveKeyID(ctx context.Context) (uint32, error)
	ListKeyVersions(ctx context.Context) ([]uint32, error)
}

// NewKeyManager creates a key manager with automatic rotation support
func NewKeyManager(ctx context.Context, provider KeyProvider, logger *slog.Logger) (*KeyManager, error) {
	km := &KeyManager{
		keys:          make(map[uint32]*KeyVersion),
		keyProvider:   provider,
		logger:        logger,
		rotationCheck: 5 * time.Minute,
	}

	// Load initial keys
	if err := km.refreshKeys(ctx); err != nil {
		return nil, fmt.Errorf("failed to load initial keys: %w", err)
	}

	// Start background key refresh
	go km.startKeyRefresh(ctx)

	return km, nil
}

func (km *KeyManager) refreshKeys(ctx context.Context) error {
	activeID, err := km.keyProvider.GetActiveKeyID(ctx)
	if err != nil {
		return err
	}

	keyVersions, err := km.keyProvider.ListKeyVersions(ctx)
	if err != nil {
		return err
	}

	km.mu.Lock()
	defer km.mu.Unlock()

	for _, keyID := range keyVersions {
		if _, exists := km.keys[keyID]; !exists {
			keyData, err := km.keyProvider.GetKey(ctx, keyID)
			if err != nil {
				km.logger.Error("failed to load key version",
					slog.Uint64("key_id", uint64(keyID)),
					slog.String("error", err.Error()))
				continue
			}
			km.keys[keyID] = &KeyVersion{
				ID:  keyID,
				Key: keyData,
			}
		}
	}

	km.activeKeyID = activeID
	km.logger.Info("keys refreshed",
		slog.Uint64("active_key_id", uint64(activeID)),
		slog.Int("total_keys", len(km.keys)))

	return nil
}

func (km *KeyManager) startKeyRefresh(ctx context.Context) {
	ticker := time.NewTicker(km.rotationCheck)
	defer ticker.Stop()

	for {
		select {
		case <-ctx.Done():
			return
		case <-ticker.C:
			if err := km.refreshKeys(ctx); err != nil {
				km.logger.Error("key refresh failed", slog.String("error", err.Error()))
			}
		}
	}
}

// Encrypt encrypts data with the current active key, prepending key ID
func (km *KeyManager) Encrypt(plaintext []byte) ([]byte, error) {
	km.mu.RLock()
	activeKey, exists := km.keys[km.activeKeyID]
	keyID := km.activeKeyID
	km.mu.RUnlock()

	if !exists {
		return nil, ErrKeyNotFound
	}

	block, err := aes.NewCipher(activeKey.Key)
	if err != nil {
		return nil, err
	}

	gcm, err := cipher.NewGCM(block)
	if err != nil {
		return nil, err
	}

	nonce := make([]byte, gcm.NonceSize())
	if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
		return nil, err
	}

	// Format: [4-byte key ID][nonce][ciphertext+tag]
	ciphertext := gcm.Seal(nonce, nonce, plaintext, nil)

	result := make([]byte, 4+len(ciphertext))
	binary.BigEndian.PutUint32(result[:4], keyID)
	copy(result[4:], ciphertext)

	km.logger.Debug("data encrypted",
		slog.Uint64("key_id", uint64(keyID)),
		slog.Int("plaintext_len", len(plaintext)))

	return result, nil
}

// Decrypt decrypts data using the key ID embedded in the ciphertext
func (km *KeyManager) Decrypt(ciphertext []byte) ([]byte, error) {
	if len(ciphertext) < 4 {
		return nil, ErrInvalidKeyID
	}

	keyID := binary.BigEndian.Uint32(ciphertext[:4])
	encryptedData := ciphertext[4:]

	km.mu.RLock()
	keyVersion, exists := km.keys[keyID]
	km.mu.RUnlock()

	if !exists {
		km.logger.Warn("decryption attempted with unknown key",
			slog.Uint64("key_id", uint64(keyID)))
		return nil, ErrKeyNotFound
	}

	block, err := aes.NewCipher(keyVersion.Key)
	if err != nil {
		return nil, err
	}

	gcm, err := cipher.NewGCM(block)
	if err != nil {
		return nil, err
	}

	nonceSize := gcm.NonceSize()
	if len(encryptedData) < nonceSize {
		return nil, ErrDecryptionFailed
	}

	nonce, ciphertextOnly := encryptedData[:nonceSize], encryptedData[nonceSize:]

	plaintext, err := gcm.Open(nil, nonce, ciphertextOnly, nil)
	if err != nil {
		km.logger.Warn("decryption failed",
			slog.Uint64("key_id", uint64(keyID)),
			slog.String("error", err.Error()))
		return nil, ErrDecryptionFailed
	}

	km.logger.Debug("data decrypted",
		slog.Uint64("key_id", uint64(keyID)))

	return plaintext, nil
}

// ReEncrypt re-encrypts data with the current active key
func (km *KeyManager) ReEncrypt(ciphertext []byte) ([]byte, bool, error) {
	keyID := binary.BigEndian.Uint32(ciphertext[:4])

	km.mu.RLock()
	activeKeyID := km.activeKeyID
	km.mu.RUnlock()

	// Already using active key
	if keyID == activeKeyID {
		return ciphertext, false, nil
	}

	// Decrypt with old key, re-encrypt with new key
	plaintext, err := km.Decrypt(ciphertext)
	if err != nil {
		return nil, false, err
	}

	newCiphertext, err := km.Encrypt(plaintext)
	if err != nil {
		return nil, false, err
	}

	km.logger.Info("data re-encrypted",
		slog.Uint64("old_key_id", uint64(keyID)),
		slog.Uint64("new_key_id", uint64(activeKeyID)))

	return newCiphertext, true, nil
}

// EncryptString convenience method returning base64
func (km *KeyManager) EncryptString(plaintext string) (string, error) {
	ciphertext, err := km.Encrypt([]byte(plaintext))
	if err != nil {
		return "", err
	}
	return base64.StdEncoding.EncodeToString(ciphertext), nil
}

// DecryptString convenience method accepting base64
func (km *KeyManager) DecryptString(encrypted string) (string, error) {
	ciphertext, err := base64.StdEncoding.DecodeString(encrypted)
	if err != nil {
		return "", err
	}
	plaintext, err := km.Decrypt(ciphertext)
	if err != nil {
		return "", err
	}
	return string(plaintext), nil
}
```

