**PRODUCTION PATTERN**:

```csharp
using System;
using System.IO;
using System.Security.Cryptography;
using System.Text;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

namespace MyApp.Security
{
    public interface IKeyProvider
    {
        Task<byte[]> GetKeyAsync(string keyId);
        Task<string> GetCurrentKeyIdAsync();
    }

    // Environment variable-based provider for containers/Kubernetes
    public class EnvironmentKeyProvider : IKeyProvider
    {
        private readonly ILogger<EnvironmentKeyProvider> _logger;

        public EnvironmentKeyProvider(ILogger<EnvironmentKeyProvider> logger)
        {
            _logger = logger;
        }

        public Task<byte[]> GetKeyAsync(string keyId)
        {
            var envVarName = $"ENCRYPTION_KEY_{keyId.ToUpperInvariant()}";
            var keyBase64 = Environment.GetEnvironmentVariable(envVarName);

            if (string.IsNullOrEmpty(keyBase64))
            {
                _logger.LogError("Encryption key not found: {KeyId}", keyId);
                throw new CryptographicException($"Key not found: {keyId}");
            }

            return Task.FromResult(Convert.FromBase64String(keyBase64));
        }

        public Task<string> GetCurrentKeyIdAsync()
        {
            var currentKeyId = Environment.GetEnvironmentVariable("ENCRYPTION_CURRENT_KEY_ID");
            return Task.FromResult(currentKeyId ?? "v1");
        }
    }

    // HashiCorp Vault provider
    public class VaultKeyProvider : IKeyProvider
    {
        private readonly HttpClient _httpClient;
        private readonly string _vaultAddress;
        private readonly ILogger<VaultKeyProvider> _logger;

        public VaultKeyProvider(IConfiguration config, ILogger<VaultKeyProvider> logger)
        {
            _logger = logger;
            _vaultAddress = config["Vault:Address"];
            _httpClient = new HttpClient();

            // Use Kubernetes service account token for authentication
            var token = File.ReadAllText("/var/run/secrets/kubernetes.io/serviceaccount/token");
            _httpClient.DefaultRequestHeaders.Add("X-Vault-Token", token);
        }

        public async Task<byte[]> GetKeyAsync(string keyId)
        {
            var response = await _httpClient.GetAsync(
                $"{_vaultAddress}/v1/secret/data/encryption-keys/{keyId}");
            response.EnsureSuccessStatusCode();

            var json = await response.Content.ReadAsStringAsync();
            var data = System.Text.Json.JsonDocument.Parse(json);
            var keyBase64 = data.RootElement
                .GetProperty("data")
                .GetProperty("data")
                .GetProperty("key")
                .GetString();

            _logger.LogInformation("Retrieved encryption key: {KeyId}", keyId);
            return Convert.FromBase64String(keyBase64!);
        }

        public async Task<string> GetCurrentKeyIdAsync()
        {
            var response = await _httpClient.GetAsync(
                $"{_vaultAddress}/v1/secret/data/encryption-keys/current");
            var json = await response.Content.ReadAsStringAsync();
            var data = System.Text.Json.JsonDocument.Parse(json);
            return data.RootElement
                .GetProperty("data")
                .GetProperty("data")
                .GetProperty("keyId")
                .GetString() ?? "v1";
        }
    }

    public class AuthenticatedEncryptionService
    {
        private readonly IKeyProvider _keyProvider;
        private readonly ILogger<AuthenticatedEncryptionService> _logger;
        private const int NonceSize = 12; // 96 bits for GCM
        private const int TagSize = 16;   // 128 bits authentication tag
        private const int KeyIdSize = 8;  // Key version identifier

        public AuthenticatedEncryptionService(
            IKeyProvider keyProvider,
            ILogger<AuthenticatedEncryptionService> logger)
        {
            _keyProvider = keyProvider;
            _logger = logger;
        }

        public async Task<string> EncryptAsync(string plainText, string? associatedData = null)
        {
            if (string.IsNullOrEmpty(plainText))
                throw new ArgumentException("Plaintext cannot be empty", nameof(plainText));

            try
            {
                // Get current key for new encryptions
                var keyId = await _keyProvider.GetCurrentKeyIdAsync();
                var key = await _keyProvider.GetKeyAsync(keyId);

                // Validate key size (256 bits for AES-256)
                if (key.Length != 32)
                    throw new CryptographicException("Invalid key size. Expected 256-bit key.");

                byte[] plainBytes = Encoding.UTF8.GetBytes(plainText);
                byte[] keyIdBytes = Encoding.UTF8.GetBytes(keyId.PadRight(KeyIdSize).Substring(0, KeyIdSize));
                byte[] nonce = new byte[NonceSize];
                byte[] cipherText = new byte[plainBytes.Length];
                byte[] tag = new byte[TagSize];

                // Generate cryptographically secure random nonce
                using (var rng = RandomNumberGenerator.Create())
                {
                    rng.GetBytes(nonce);
                }

                // Use AES-GCM for authenticated encryption
                using (var aesGcm = new AesGcm(key, TagSize))
                {
                    byte[]? aad = associatedData != null 
                        ? Encoding.UTF8.GetBytes(associatedData) 
                        : null;

                    aesGcm.Encrypt(nonce, plainBytes, cipherText, tag, aad);
                }

                // Format: keyId (8) + nonce (12) + tag (16) + ciphertext (variable)
                byte[] result = new byte[KeyIdSize + NonceSize + TagSize + cipherText.Length];
                Buffer.BlockCopy(keyIdBytes, 0, result, 0, KeyIdSize);
                Buffer.BlockCopy(nonce, 0, result, KeyIdSize, NonceSize);
                Buffer.BlockCopy(tag, 0, result, KeyIdSize + NonceSize, TagSize);
                Buffer.BlockCopy(cipherText, 0, result, KeyIdSize + NonceSize + TagSize, cipherText.Length);

                _logger.LogDebug("Data encrypted with key version: {KeyId}", keyId);
                return Convert.ToBase64String(result);
            }
            catch (CryptographicException ex)
            {
                _logger.LogError(ex, "Encryption failed");
                throw;
            }
        }

        public async Task<string> DecryptAsync(string cipherTextBase64, string? associatedData = null)
        {
            if (string.IsNullOrEmpty(cipherTextBase64))
                throw new ArgumentException("Ciphertext cannot be empty", nameof(cipherTextBase64));

            try
            {
                byte[] fullCipher = Convert.FromBase64String(cipherTextBase64);

                if (fullCipher.Length < KeyIdSize + NonceSize + TagSize)
                    throw new CryptographicException("Invalid ciphertext format");

                // Extract components
                byte[] keyIdBytes = new byte[KeyIdSize];
                byte[] nonce = new byte[NonceSize];
                byte[] tag = new byte[TagSize];
                byte[] cipherText = new byte[fullCipher.Length - KeyIdSize - NonceSize - TagSize];

                Buffer.BlockCopy(fullCipher, 0, keyIdBytes, 0, KeyIdSize);
                Buffer.BlockCopy(fullCipher, KeyIdSize, nonce, 0, NonceSize);
                Buffer.BlockCopy(fullCipher, KeyIdSize + NonceSize, tag, 0, TagSize);
                Buffer.BlockCopy(fullCipher, KeyIdSize + NonceSize + TagSize, cipherText, 0, cipherText.Length);

                string keyId = Encoding.UTF8.GetString(keyIdBytes).Trim();
                byte[] key = await _keyProvider.GetKeyAsync(keyId);

                byte[] plainBytes = new byte[cipherText.Length];

                using (var aesGcm = new AesGcm(key, TagSize))
                {
                    byte[]? aad = associatedData != null 
                        ? Encoding.UTF8.GetBytes(associatedData) 
                        : null;

                    aesGcm.Decrypt(nonce, cipherText, tag, plainBytes, aad);
                }

                _logger.LogDebug("Data decrypted with key version: {KeyId}", keyId);
                return Encoding.UTF8.GetString(plainBytes);
            }
            catch (AuthenticationTagMismatchException ex)
            {
                _logger.LogWarning(ex, "Decryption failed - data may have been tampered with");
                throw new CryptographicException("Data integrity verification failed", ex);
            }
            catch (CryptographicException ex)
            {
                _logger.LogError(ex, "Decryption failed");
                throw;
            }
        }

        // Re-encrypt data with current key version (for key rotation)
        public async Task<string> RotateEncryptionAsync(string oldCipherText, string? associatedData = null)
        {
            var plainText = await DecryptAsync(oldCipherText, associatedData);
            return await EncryptAsync(plainText, associatedData);
        }
    }

    // Dependency injection setup
    public static class EncryptionServiceExtensions
    {
        public static IServiceCollection AddEncryptionServices(
            this IServiceCollection services,
            IConfiguration configuration)
        {
            var keySource = configuration["Encryption:KeySource"] ?? "environment";

            switch (keySource.ToLower())
            {
                case "vault":
                    services.AddSingleton<IKeyProvider, VaultKeyProvider>();
                    break;
                case "environment":
                default:
                    services.AddSingleton<IKeyProvider, EnvironmentKeyProvider>();
                    break;
            }

            services.AddSingleton<AuthenticatedEncryptionService>();
            return services;
        }
    }
}
