Key rotation is essential for limiting the impact of key compromise and meeting compliance requirements. In production, you should use a dedicated secrets manager like AWS KMS, HashiCorp Vault, or Azure Key Vault, combined with envelope encryption for efficient key rotation.

**PRODUCTION PATTERN**:

```javascript
const crypto = require('crypto');
const { SecretsManagerClient, GetSecretValueCommand } = require('@aws-sdk/client-secrets-manager');
const { KMSClient, GenerateDataKeyCommand, DecryptCommand } = require('@aws-sdk/client-kms');

class ProductionEncryptionService {
  static ALGORITHM = 'aes-256-gcm';
  static IV_LENGTH = 16;
  static KEY_VERSION_HEADER = 'v';

  constructor(config) {
    this.kmsClient = new KMSClient({ region: config.region });
    this.secretsClient = new SecretsManagerClient({ region: config.region });
    this.kmsKeyId = config.kmsKeyId;
    this.secretName = config.secretName;
    this.keyCache = new Map();
    this.currentKeyVersion = null;
    this.logger = config.logger || console;
  }

  async initialize() {
    // Load key versions from secrets manager
    const command = new GetSecretValueCommand({ SecretId: this.secretName });
    const response = await this.secretsClient.send(command);
    const keyConfig = JSON.parse(response.SecretString);

    this.currentKeyVersion = keyConfig.currentVersion;

    // Cache all active key versions for decryption
    for (const [version, encryptedKey] of Object.entries(keyConfig.keys)) {
      const decryptedKey = await this.decryptDataKey(encryptedKey);
      this.keyCache.set(version, decryptedKey);
    }

    this.logger.info('Encryption service initialized', {
      currentKeyVersion: this.currentKeyVersion,
      cachedVersions: Array.from(this.keyCache.keys())
    });
  }

  async decryptDataKey(encryptedKeyBase64) {
    const command = new DecryptCommand({
      CiphertextBlob: Buffer.from(encryptedKeyBase64, 'base64'),
      KeyId: this.kmsKeyId
    });
    const response = await this.kmsClient.send(command);
    return Buffer.from(response.Plaintext);
  }

  async generateNewDataKey() {
    // Generate new data key encrypted by KMS master key
    const command = new GenerateDataKeyCommand({
      KeyId: this.kmsKeyId,
      KeySpec: 'AES_256'
    });
    const response = await this.kmsClient.send(command);

    return {
      plaintext: Buffer.from(response.Plaintext),
      encrypted: Buffer.from(response.CiphertextBlob).toString('base64')
    };
  }

  encrypt(plaintext, context = {}) {
    const key = this.keyCache.get(this.currentKeyVersion);
    if (!key) {
      throw new Error(`Current key version ${this.currentKeyVersion} not found`);
    }

    const iv = crypto.randomBytes(ProductionEncryptionService.IV_LENGTH);
    const cipher = crypto.createCipheriv(
      ProductionEncryptionService.ALGORITHM,
      key,
      iv
    );

    // Add AAD (Additional Authenticated Data) for context binding
    if (context.userId) {
      cipher.setAAD(Buffer.from(context.userId));
    }

    let encrypted = cipher.update(plaintext, 'utf8');
    encrypted = Buffer.concat([encrypted, cipher.final()]);
    const authTag = cipher.getAuthTag();

    // Prepend version identifier for key rotation support
    const versionedCiphertext = Buffer.concat([
      Buffer.from(`${ProductionEncryptionService.KEY_VERSION_HEADER}${this.currentKeyVersion}:`),
      iv,
      authTag,
      encrypted
    ]);

    this.logger.debug('Data encrypted', {
      keyVersion: this.currentKeyVersion,
      dataLength: plaintext.length
    });

    return versionedCiphertext.toString('base64');
  }

  decrypt(ciphertextBase64, context = {}) {
    const ciphertext = Buffer.from(ciphertextBase64, 'base64');

    // Extract version from header
    const headerEnd = ciphertext.indexOf(':'.charCodeAt(0));
    const header = ciphertext.slice(0, headerEnd).toString();
    const keyVersion = header.replace(ProductionEncryptionService.KEY_VERSION_HEADER, '');

    const key = this.keyCache.get(keyVersion);
    if (!key) {
      this.logger.error('Key version not found for decryption', { keyVersion });
      throw new Error(`Key version ${keyVersion} not available`);
    }

    const dataStart = headerEnd + 1;
    const iv = ciphertext.slice(dataStart, dataStart + 16);
    const authTag = ciphertext.slice(dataStart + 16, dataStart + 32);
    const encryptedData = ciphertext.slice(dataStart + 32);

    const decipher = crypto.createDecipheriv(
      ProductionEncryptionService.ALGORITHM,
      key,
      iv
    );

    decipher.setAuthTag(authTag);

    if (context.userId) {
      decipher.setAAD(Buffer.from(context.userId));
    }

    let decrypted = decipher.update(encryptedData);
    decrypted = Buffer.concat([decrypted, decipher.final()]);

    return decrypted.toString('utf8');
  }

  // Re-encrypt data with current key version
  async reencrypt(ciphertextBase64, context = {}) {
    const plaintext = this.decrypt(ciphertextBase64, context);
    return this.encrypt(plaintext, context);
  }

  // Batch re-encryption for key rotation
  async rotateEncryptedRecords(records, batchSize = 100) {
    const results = { success: 0, failed: 0, errors: [] };

    for (let i = 0; i < records.length; i += batchSize) {
      const batch = records.slice(i, i + batchSize);

      for (const record of batch) {
        try {
          const reencrypted = await this.reencrypt(
            record.encryptedData,
            { userId: record.userId }
          );
          record.encryptedData = reencrypted;
          results.success++;
        } catch (error) {
          results.failed++;
          results.errors.push({
            recordId: record.id,
            error: error.message
          });
          this.logger.error('Re-encryption failed', {
            recordId: record.id,
            error: error.message
          });
        }
      }

      this.logger.info('Key rotation batch completed', {
        processed: Math.min(i + batchSize, records.length),
        total: records.length
      });
    }

    return results;
  }
}

