**PRODUCTION PATTERN**:

```go
package encryption

import (
	"context"
	"crypto/aes"
	"crypto/cipher"
	"crypto/rand"
	"encoding/base64"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"log/slog"
	"sync"
	"time"

	secretmanager "cloud.google.com/go/secretmanager/apiv1"
	secretmanagerpb "cloud.google.com/go/secretmanager/apiv1/secretmanagerpb"
)

// KeyVersion tracks which key version encrypted the data
type EncryptedPayload struct {
	KeyVersion string `json:"v"`
	Ciphertext string `json:"c"`
}

// KeyManager handles secure key retrieval and rotation
type KeyManager struct {
	client       *secretmanager.Client
	projectID    string
	secretID     string
	keyCache     map[string][]byte
	cacheMutex   sync.RWMutex
	currentKeyID string
	logger       *slog.Logger
}

func NewKeyManager(ctx context.Context, projectID, secretID string, logger *slog.Logger) (*KeyManager, error) {
	client, err := secretmanager.NewClient(ctx)
	if err != nil {
		return nil, fmt.Errorf("failed to create secret manager client: %w", err)
	}

	km := &KeyManager{
		client:    client,
		projectID: projectID,
		secretID:  secretID,
		keyCache:  make(map[string][]byte),
		logger:    logger,
	}

	// Load current key version on startup
	if err := km.refreshCurrentKey(ctx); err != nil {
		return nil, err
	}

	// Start background key refresh
	go km.startKeyRefresh(ctx)

	return km, nil
}

func (km *KeyManager) refreshCurrentKey(ctx context.Context) error {
	name := fmt.Sprintf("projects/%s/secrets/%s/versions/latest", km.projectID, km.secretID)

	req := &secretmanagerpb.AccessSecretVersionRequest{Name: name}
	result, err := km.client.AccessSecretVersion(ctx, req)
	if err != nil {
		return fmt.Errorf("failed to access secret: %w", err)
	}

	key := result.Payload.Data
	if len(key) != 32 {
		return errors.New("encryption key must be 32 bytes")
	}

	// Extract version ID from the full resource name
	versionID := result.Name

	km.cacheMutex.Lock()
	km.keyCache[versionID] = key
	km.currentKeyID = versionID
	km.cacheMutex.Unlock()

	km.logger.Info("encryption key refreshed",
		"version", versionID,
		"cached_keys", len(km.keyCache))

	return nil
}

func (km *KeyManager) startKeyRefresh(ctx context.Context) {
	ticker := time.NewTicker(5 * time.Minute)
	defer ticker.Stop()

	for {
		select {
		case <-ctx.Done():
			return
		case <-ticker.C:
			if err := km.refreshCurrentKey(ctx); err != nil {
				km.logger.Error("key refresh failed", "error", err)
			}
		}
	}
}

func (km *KeyManager) getKeyByVersion(ctx context.Context, versionID string) ([]byte, error) {
	km.cacheMutex.RLock()
	if key, ok := km.keyCache[versionID]; ok {
		km.cacheMutex.RUnlock()
		return key, nil
	}
	km.cacheMutex.RUnlock()

	// Fetch old key version for decryption
	req := &secretmanagerpb.AccessSecretVersionRequest{Name: versionID}
	result, err := km.client.AccessSecretVersion(ctx, req)
	if err != nil {
		return nil, fmt.Errorf("failed to access key version %s: %w", versionID, err)
	}

	key := result.Payload.Data

	km.cacheMutex.Lock()
	km.keyCache[versionID] = key
	km.cacheMutex.Unlock()

	km.logger.Info("loaded historical key version", "version", versionID)

	return key, nil
}

// Encrypt uses the current key version
func (km *KeyManager) Encrypt(ctx context.Context, plaintext []byte) (string, error) {
	km.cacheMutex.RLock()
	key := km.keyCache[km.currentKeyID]
	keyVersion := km.currentKeyID
	km.cacheMutex.RUnlock()

	block, err := aes.NewCipher(key)
	if err != nil {
		return "", fmt.Errorf("cipher creation failed: %w", err)
	}

	gcm, err := cipher.NewGCM(block)
	if err != nil {
		return "", fmt.Errorf("GCM creation failed: %w", err)
	}

	nonce := make([]byte, gcm.NonceSize())
	if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
		return "", fmt.Errorf("nonce generation failed: %w", err)
	}

	ciphertext := gcm.Seal(nonce, nonce, plaintext, nil)

	payload := EncryptedPayload{
		KeyVersion: keyVersion,
		Ciphertext: base64.StdEncoding.EncodeToString(ciphertext),
	}

	result, err := json.Marshal(payload)
	if err != nil {
		return "", fmt.Errorf("payload marshal failed: %w", err)
	}

	return base64.StdEncoding.EncodeToString(result), nil
}

// Decrypt supports any historical key version
func (km *KeyManager) Decrypt(ctx context.Context, encoded string) ([]byte, error) {
	data, err := base64.StdEncoding.DecodeString(encoded)
	if err != nil {
		return nil, fmt.Errorf("base64 decode failed: %w", err)
	}

	var payload EncryptedPayload
	if err := json.Unmarshal(data, &payload); err != nil {
		return nil, fmt.Errorf("payload unmarshal failed: %w", err)
	}

	key, err := km.getKeyByVersion(ctx, payload.KeyVersion)
	if err != nil {
		return nil, err
	}

	ciphertext, err := base64.StdEncoding.DecodeString(payload.Ciphertext)
	if err != nil {
		return nil, fmt.Errorf("ciphertext decode failed: %w", err)
	}

	block, err := aes.NewCipher(key)
	if err != nil {
		return nil, fmt.Errorf("cipher creation failed: %w", err)
	}

	gcm, err := cipher.NewGCM(block)
	if err != nil {
		return nil, fmt.Errorf("GCM creation failed: %w", err)
	}

	if len(ciphertext) < gcm.NonceSize() {
		return nil, errors.New("ciphertext too short")
	}

	nonce, ciphertext := ciphertext[:gcm.NonceSize()], ciphertext[gcm.NonceSize():]
	plaintext, err := gcm.Open(nil, nonce, ciphertext, nil)
	if err != nil {
		km.logger.Warn("decryption failed",
			"key_version", payload.KeyVersion,
			"error", "authentication failed")
		return nil, fmt.Errorf("decryption failed: %w", err)
	}

	return plaintext, nil
}

// Close releases resources
func (km *KeyManager) Close() error {
	// Clear keys from memory
	km.cacheMutex.Lock()
	for k := range km.keyCache {
		delete(km.keyCache, k)
	}
	km.cacheMutex.Unlock()

	return km.client.Close()
}
