2. **Key Rotation Automation**:
```csharp
// Azure Function for automated key rotation
[FunctionName("RotateEncryptionKey")]
public async Task RotateKey([TimerTrigger("0 0 0 1 * *")] TimerInfo timer)
{
    // Monthly key rotation
    var newKey = await _keyClient.CreateKeyAsync(_keyName, KeyType.Oct);
    _logger.LogInformation("New encryption key created: {Version}", newKey.Value.Properties.Version);

    // Trigger background re-encryption job
    await _queueClient.SendMessageAsync(new { Action = "ReEncrypt", KeyVersion = newKey.Value.Properties.Version });
}
