3. **Audit Logging and Monitoring**:
```csharp
// Log all cryptographic operations for compliance
public async Task<string> EncryptWithAuditAsync(string plainText, string userId, string purpose)
{
    var stopwatch = Stopwatch.StartNew();

    try
    {
        string result = await EncryptAsync(plainText, purpose);

        _logger.LogInformation(
            "Encryption operation completed. User: {UserId}, Purpose: {Purpose}, Duration: {Duration}ms",
            userId, purpose, stopwatch.ElapsedMilliseconds);

        // Emit metric for monitoring
        _metrics.RecordEncryptionOperation(purpose, stopwatch.ElapsedMilliseconds);

        return result;
    }
    catch (CryptographicException ex)
    {
        _logger.LogError(ex, 
            "Encryption failed. User: {UserId}, Purpose: {Purpose}", 
            userId, purpose);

        // Alert security team on cryptographic failures
        await _alertService.SendCriticalAlertAsync(
            "Cryptographic Operation Failed",
            $"User {userId} encountered encryption failure for {purpose}");

        throw;
    }
}
